cd /tmp/sv-d50a5f4a23504634aea9d866c0aeeddd/advanced-multi-complexity && dotnet package list --format json 2>/dev/null | tee after-cpm-packages.json | python3 -c "
import json, sys
data = json.load(sys.stdin)
for p in data['projects']:
    name = p['path'].split('/')[-1]
    for fw in p['frameworks']:
        for pkg in fw['topLevelPackages']:
            print(f'{name:20s} {fw[\"framework\"]:10s} {pkg[\"id\"]:50s} {pkg[\"resolvedVersion\"]}')
"

